import { useEffect, useState } from "react"
import { Code, Eye, Mail, Pencil, Plus, Save, Trash2, X } from "lucide-react"

import { Badge } from "@ui-core/components/ui/badge"
import { Button } from "@ui-core/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@ui-core/components/ui/card"
import { TableToolbar, TablePagination } from "@ui-core/components/ui/table"

import type { EmailTemplate } from "../types/sma"
import { emailTemplatesApi } from "../services/api"

type EditState = { id: string; key: string; name: string; subject_template: string; body_template: string }
type EditorTab = "code" | "preview"

const PAGE_SIZE = 25

const DEFAULT_HTML_TEMPLATE = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <title>{{subject}}</title>
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
</head>

<body style="margin:0; padding:0; font-family: Arial, sans-serif; background-color:#e6f4f9;">

  <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#e6f4f9; padding:20px;">
    <tr>
      <td align="center">

        <!-- Container -->
        <table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff; border-radius:8px; overflow:hidden; box-shadow:0 4px 10px rgba(0,0,0,0.05);">

          <!-- Header -->
          <tr>
            <td style="background:#0d5c73; padding:20px; text-align:center;">
              <img src="data:image/png;base64," alt="Logo SMA" style="max-width:180px;">
            </td>
          </tr>

          <!-- Title -->
          <tr>
            <td style="padding:30px 20px 10px 20px; text-align:center;">
              <h1 style="margin:0; color:#0d5c73;">Bonjour {{contact_name}},</h1>
            </td>
          </tr>

          <!-- Intro -->
          <tr>
            <td style="padding:10px 30px; color:#333; font-size:16px; line-height:1.5;">
              <p>
                Nous vous rappelons que la formation <strong>{{course_label}}</strong>
                de <strong>{{organization_name}}</strong> arrive à échéance le <strong>{{due_date}}</strong>.
              </p>
              <p>
                Afin de maintenir la conformité de votre établissement, nous vous invitons à procéder rapidement au renouvellement.
              </p>
            </td>
          </tr>

          <!-- CTA -->
          <tr>
            <td align="center" style="padding:20px;">
              <a href="#" style="background:#0d5c73; color:#fff; text-decoration:none; padding:15px 25px; border-radius:5px; display:inline-block; font-weight:bold;">
                Prendre rendez-vous
              </a>
            </td>
          </tr>

          <!-- Footer -->
          <tr>
            <td style="background:#f0f0f0; padding:20px; text-align:center; font-size:14px; color:#666;">
              <p style="margin:5px 0;">SMA - Votre partenaire de croissance</p>
              <p style="margin:5px 0;">contact@sma.fr | 01 23 45 67 89</p>
            </td>
          </tr>

        </table>

      </td>
    </tr>
  </table>

</body>
</html>`

function HtmlEditor({
  value,
  onChange,
  rows = 20,
}: {
  value: string
  onChange: (v: string) => void
  rows?: number
}) {
  const [tab, setTab] = useState<EditorTab>("code")

  return (
    <div className="space-y-0 rounded-md border border-input overflow-hidden">
      <div className="flex border-b border-input bg-muted/40">
        <button
          type="button"
          onClick={() => setTab("code")}
          className={`flex items-center gap-1.5 px-4 py-2 text-sm font-medium transition-colors ${
            tab === "code"
              ? "bg-background text-foreground border-b-2 border-primary -mb-px"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          <Code className="h-3.5 w-3.5" /> Code HTML
        </button>
        <button
          type="button"
          onClick={() => setTab("preview")}
          className={`flex items-center gap-1.5 px-4 py-2 text-sm font-medium transition-colors ${
            tab === "preview"
              ? "bg-background text-foreground border-b-2 border-primary -mb-px"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          <Eye className="h-3.5 w-3.5" /> Aperçu
        </button>
      </div>

      {tab === "code" ? (
        <textarea
          value={value}
          onChange={e => onChange(e.target.value)}
          rows={rows}
          required
          className="w-full px-3 py-2 text-sm font-mono bg-background focus:outline-none focus:ring-2 focus:ring-ring resize-y"
        />
      ) : (
        <iframe
          srcDoc={value}
          sandbox="allow-same-origin"
          className="w-full bg-white"
          style={{ height: `${rows * 1.5}rem`, border: "none" }}
          title="Aperçu e-mail"
        />
      )}
    </div>
  )
}

export default function EmailTemplatesPage() {
  const [items, setItems] = useState<EmailTemplate[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [newKey, setNewKey] = useState("")
  const [newName, setNewName] = useState("")
  const [newSubject, setNewSubject] = useState("")
  const [newBody, setNewBody] = useState(DEFAULT_HTML_TEMPLATE)
  const [creating, setCreating] = useState(false)
  const [editState, setEditState] = useState<EditState | null>(null)
  const [saving, setSaving] = useState(false)
  const [search, setSearch] = useState("")
  const [page, setPage] = useState(0)
  const [totalCount, setTotalCount] = useState(0)

  useEffect(() => {
    const timer = setTimeout(load, 300)
    return () => clearTimeout(timer)
  }, [search, page])

  async function load() {
    setLoading(true); setError(null)
    try {
      const d = await emailTemplatesApi.list({ search: search || undefined, limit: PAGE_SIZE, offset: page * PAGE_SIZE })
      setItems(d.items); setTotalCount(d.count)
    }
    catch (e) { setError(e instanceof Error ? e.message : "Erreur") }
    finally { setLoading(false) }
  }

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault(); if (!newKey.trim() || !newName.trim() || !newSubject.trim() || !newBody.trim()) return
    setCreating(true)
    try {
      const c = await emailTemplatesApi.create({ key: newKey.trim(), name: newName.trim(), subject_template: newSubject.trim(), body_template: newBody })
      setItems(p => [c, ...p]); setNewKey(""); setNewName(""); setNewSubject(""); setNewBody(DEFAULT_HTML_TEMPLATE)
    } catch (e) { alert(e instanceof Error ? e.message : "Erreur") }
    finally { setCreating(false) }
  }

  async function handleArchive(id: string) {
    if (!confirm("Archiver ce modèle ?")) return
    try { await emailTemplatesApi.archive(id); setItems(p => p.filter(i => i.id !== id)) }
    catch (e) { alert(e instanceof Error ? e.message : "Erreur") }
  }

  async function handleSave(id: string) {
    if (!editState) return; setSaving(true)
    try {
      const u = await emailTemplatesApi.update(id, {
        key: editState.key.trim(), name: editState.name.trim(),
        subject_template: editState.subject_template.trim(),
        body_template: editState.body_template,
      })
      setItems(p => p.map(i => i.id === id ? u : i)); setEditState(null)
    } catch (e) { alert(e instanceof Error ? e.message : "Erreur") }
    finally { setSaving(false) }
  }

  return (
    <div className="space-y-6">
      <header className="space-y-2">
        <Badge variant="gradient">Paramétrage</Badge>
        <h1 className="text-2xl font-bold tracking-tight flex items-center gap-2">
          <Mail className="h-6 w-6 text-primary" /> Modèles d'e-mail
        </h1>
        <p className="text-muted-foreground max-w-2xl">
          Variables disponibles : {"{{organization_name}}"}, {"{{course_label}}"}, {"{{due_date}}"}, {"{{contact_name}}"}.
          Les templates utilisent la structure HTML SMA (table-based, fond #e6f4f9, header #0d5c73).
        </p>
      </header>

      <Card>
        <CardHeader><CardTitle className="text-lg flex items-center gap-2"><Plus className="h-4 w-4" /> Nouveau modèle</CardTitle>
          <CardDescription>Le corps est pré-rempli avec la structure HTML SMA standard. Personnalisez-le dans l'onglet Code puis vérifiez le rendu dans Aperçu.</CardDescription></CardHeader>
        <CardContent>
          <form onSubmit={handleCreate} className="space-y-3">
            <div className="grid gap-3 sm:grid-cols-2">
              <div className="space-y-1">
                <label className="text-sm font-medium">Clé <span className="text-destructive">*</span></label>
                <input value={newKey} onChange={e => setNewKey(e.target.value)} required maxLength={100} placeholder="relance_standard"
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring" />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-medium">Libellé <span className="text-destructive">*</span></label>
                <input value={newName} onChange={e => setNewName(e.target.value)} required maxLength={255}
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring" />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-medium">Sujet <span className="text-destructive">*</span></label>
              <input value={newSubject} onChange={e => setNewSubject(e.target.value)} required maxLength={500}
                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring" />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-medium">Corps HTML <span className="text-destructive">*</span></label>
              <HtmlEditor value={newBody} onChange={setNewBody} rows={22} />
            </div>
            <Button type="submit" disabled={creating}>{creating ? "Création…" : "Créer le modèle"}</Button>
          </form>
        </CardContent>
      </Card>

      <TableToolbar
        onSearch={(v) => { setSearch(v); setPage(0) }}
        searchPlaceholder="Rechercher un modèle…"
      />

      <div className="space-y-3">
        {loading && <p className="text-sm text-muted-foreground">Chargement…</p>}
        {error && <Card className="border-destructive/50"><CardContent className="pt-4"><p className="text-sm text-destructive">{error}</p></CardContent></Card>}
        {!loading && !error && items.length === 0 && <Card><CardContent className="pt-6 text-center text-sm text-muted-foreground">Aucun modèle.</CardContent></Card>}

        {items.map(item => editState?.id === item.id ? (
          <Card key={item.id} className="border-primary/40">
            <CardContent className="pt-4 space-y-3">
              <div className="grid gap-3 sm:grid-cols-2">
                <input value={editState.key} onChange={e => setEditState(p => p && { ...p, key: e.target.value })} placeholder="Clé"
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring" />
                <input value={editState.name} onChange={e => setEditState(p => p && { ...p, name: e.target.value })} placeholder="Libellé"
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring" />
              </div>
              <input value={editState.subject_template} onChange={e => setEditState(p => p && { ...p, subject_template: e.target.value })} placeholder="Sujet"
                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring" />
              <div className="space-y-1">
                <label className="text-sm font-medium">Corps HTML</label>
                <HtmlEditor value={editState.body_template} onChange={v => setEditState(p => p && { ...p, body_template: v })} rows={22} />
              </div>
              <div className="flex gap-2">
                <Button size="sm" onClick={() => handleSave(item.id)} disabled={saving}><Save className="h-3 w-3 mr-1" />{saving ? "…" : "Enregistrer"}</Button>
                <Button size="sm" variant="ghost" onClick={() => setEditState(null)}><X className="h-3 w-3 mr-1" />Annuler</Button>
              </div>
            </CardContent>
          </Card>
        ) : (
          <Card key={item.id}>
            <CardContent className="pt-4">
              <div className="flex items-start justify-between gap-4">
                <div className="min-w-0 flex-1 space-y-1">
                  <p className="font-medium">{item.name}</p>
                  <p className="text-xs text-muted-foreground">
                    <code className="bg-muted px-1 py-0.5 rounded">{item.key}</code> · Sujet : {item.subject_template}
                  </p>
                  <div className="mt-2 rounded border border-input overflow-hidden">
                    <div className="bg-muted/40 px-2 py-0.5 flex items-center gap-1 text-xs text-muted-foreground border-b border-input">
                      <Eye className="h-3 w-3" /> Aperçu
                    </div>
                    <iframe
                      srcDoc={item.body_template}
                      sandbox="allow-same-origin"
                      className="w-full bg-white pointer-events-none"
                      style={{ height: "200px", border: "none" }}
                      title={`Aperçu : ${item.name}`}
                    />
                  </div>
                </div>
                <div className="flex gap-1 shrink-0">
                  <Button size="icon" variant="ghost" title="Modifier" onClick={() => setEditState({
                    id: item.id, key: item.key, name: item.name,
                    subject_template: item.subject_template, body_template: item.body_template,
                  })}><Pencil className="h-4 w-4" /></Button>
                  <Button size="icon" variant="ghost" className="text-destructive" title="Archiver" onClick={() => handleArchive(item.id)}><Trash2 className="h-4 w-4" /></Button>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <TablePagination
        pageIndex={page}
        pageSize={PAGE_SIZE}
        totalCount={totalCount}
        pageCount={Math.ceil(totalCount / PAGE_SIZE)}
        onPageChange={setPage}
      />
    </div>
  )
}
